module tb_trojan_1;

  reg clk, reset_n, cs, we;
  reg [7:0] address;
  reg [31:0] write_data;
  wire [31:0] read_data;

  aes dut (
    .clk(clk),
    .reset_n(reset_n),
    .cs(cs),
    .we(we),
    .address(address),
    .write_data(write_data),
    .read_data(read_data)
  );

  always #5 clk = ~clk;

  task write_word;
    input [7:0] addr;
    input [31:0] data;
    begin
      @(posedge clk);
      cs = 1; we = 1;
      address = addr;
      write_data = data;
      #20;
      cs = 0; we = 0;
    end
  endtask

  task read_word;
    input  [7:0]  addr;
    output [31:0] data;
    begin
      @(posedge clk);
      cs = 1; we = 0;
      address = addr;
      #20;
      data = read_data;
      cs = 0;
    end
  endtask

  reg [31:0] r0, r1, r2, r3;
  reg [127:0] result;

  initial begin
    clk = 0; reset_n = 0; cs = 0; we = 0;
    address = 0; write_data = 0;
    #50;
    reset_n = 1;
    #20;

    // ----------------------------------------------------------------
    // Section 1 — Normal operation
