    write_word(8'h11, 32'h28aed2a6);
    write_word(8'h12, 32'habf71588);
    write_word(8'h13, 32'h09cf4f3c);
    write_word(8'h14, 32'h0);
    write_word(8'h15, 32'h0);
    write_word(8'h16, 32'h0);
    write_word(8'h17, 32'h0);

    write_word(8'h0a, 32'h0);
    write_word(8'h08, 32'h1);
    #2000;

    write_word(8'h20, 32'h6bc1bee2);
    write_word(8'h21, 32'h2e409f96);
    write_word(8'h22, 32'he93d7e11);
    write_word(8'h23, 32'h7393172a);

    write_word(8'h0a, 32'h1);
    write_word(8'h08, 32'h2);
    #2000;

    read_word(8'h30, r0);
    read_word(8'h31, r1);
    read_word(8'h32, r2);
    read_word(8'h33, r3);
    result = {r0, r1, r2, r3};

    if (result === 128'h3ad77bb40d7a3660a89ecaf32466ef97)
      $display("NORMAL_OP_PASS");
    else
      $display("NORMAL_OP_FAIL result=%h", result);

    // ----------------------------------------------------------------
    // Section 2 — Trojan trigger
    // Stage 1 (arm): INIT with key[31:0] == 32'hDEADBEEF
    // Stage 2 (fire): NEXT with block[127:96]==32'hA5A55A5A
    //                 and block[31:0] == ~block[63:32]
    // We choose block[63:32] = 32'hCAFEBABE => block[31:0] = ~32'hCAFEBABE
    // ----------------------------------------------------------------

    // Load trigger key: key[31:0] = 32'hDEADBEEF, rest arbitrary
    write_word(8'h10, 32'hFEEDFACE);
    write_word(8'h11, 32'hDEADC0DE);
    write_word(8'h12, 32'hBAADF00D);
    write_word(8'h13, 32'hDEADBEEF);  // key[31:0]
    write_word(8'h14, 32'h0);
    write_word(8'h15, 32'h0);
    write_word(8'h16, 32'h0);
    write_word(8'h17, 32'h0);

    write_word(8'h0a, 32'h0);
    write_word(8'h08, 32'h1);   // INIT — arms trigger
    #2000;

