    // block[95:64]  = arbitrary     -> BLOCK1
    // block[63:32]  = 32'hCAFEBABE -> BLOCK2
    // block[31:0]   = ~32'hCAFEBABE -> BLOCK3
    write_word(8'h20, 32'hA5A55A5A);
    write_word(8'h21, 32'h12345678);
    write_word(8'h22, 32'hCAFEBABE);
    write_word(8'h23, ~32'hCAFEBABE);

    write_word(8'h0a, 32'h1);
    write_word(8'h08, 32'h2);   // NEXT — fires trigger
